+		`Resolved configuration: jdbcUrl=${sanitizeJdbcUrl(resolvedJdbcUrl)}, username=${resolvedUsername}, password=${maskSecret(resolvedPassword)}, output=${resolvedOutput}, schema=${options.schema}`,
